import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid, Cell } from 'recharts';
import { LayoutDashboard, Truck, Map, FileText, Settings, Send, Plus, Activity } from 'lucide-react';

const Dashboard = ({ datos = [] }) => {
  // 1. PROCESAMIENTO DE DATOS REALES
  const stats = useMemo(() => {
    const total = datos.length || 0;
    // Agrupamos por hora (asumiendo columna 'hora' en tu CSV)
    const agrupados = datos.reduce((acc, curr) => {
      const h = curr.hora || '00:00';
      if (!acc[h]) acc[h] = { hora: h, arribo: 0, bipeo: 0 };
      acc[h].arribo += 1; // Ajusta según tu lógica de 'bipeo'
      acc[h].bipeo += Math.floor(Math.random() * 2); // Simulación si no está en CSV
      return acc;
    }, {});

    const chartData = Object.values(agrupados).sort((a, b) => a.hora.localeCompare(b.hora)).slice(-8);

    return {
      total: total.toLocaleString(),
      chartData: chartData.length > 0 ? chartData : defaultData
    };
  }, [datos]);

  return (
    <div className="flex h-screen bg-[#0a0f1d] text-slate-300 font-sans overflow-hidden">
      {/* SIDEBAR IZQUIERDO */}
      <aside className="w-64 bg-[#111827] flex flex-col border-r border-slate-800/50">
        <div className="p-6">
          <h1 className="text-blue-400 font-bold text-xl tracking-tight">MONITOR INHUB</h1>
          <p className="text-[10px] text-slate-500 font-medium">PROXIMAMENTE</p>
        </div>

        <nav className="flex-1 px-4 space-y-1">
          <NavItem icon={<LayoutDashboard size={18}/>} text="Command Center" active />
          <NavItem icon={<Truck size={18}/>} text="Fleet Status" />
          <NavItem icon={<Map size={18}/>} text="Route Logic" />
          <NavItem icon={<Send size={18}/>} text="Dispatch" />
          <NavItem icon={<FileText size={18}/>} text="Reports" />
          <NavItem icon={<Settings size={18}/>} text="Settings" />
        </nav>

        <div className="p-4">
          <button className="w-full bg-gradient-to-r from-blue-600 to-blue-400 text-white py-3 rounded-lg flex items-center justify-center gap-2 text-sm font-bold shadow-lg shadow-blue-500/20">
            <Plus size={16} /> NEW DISPATCH
          </button>
        </div>
      </aside>

      {/* CONTENIDO PRINCIPAL */}
      <main className="flex-1 flex flex-col overflow-y-auto">
        {/* HEADER */}
        <header className="flex justify-between items-center px-8 py-4 bg-[#0a0f1d]/50 backdrop-blur-md sticky top-0 z-10">
          <div className="flex gap-8 items-center">
            <h2 className="text-sm font-bold text-white uppercase tracking-[0.2em]">OCASA DASHBOARD</h2>
            <nav className="flex gap-6 text-[10px] font-bold text-slate-500 uppercase tracking-widest">
              <span className="hover:text-blue-400 cursor-pointer">Network Map</span>
              <span className="hover:text-blue-400 cursor-pointer">Global Alerts</span>
            </nav>
          </div>
          <div className="flex items-center gap-2 px-3 py-1 bg-green-500/10 border border-green-500/20 rounded-full">
            <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse" />
            <span className="text-[10px] text-green-500 font-bold uppercase">System Status</span>
          </div>
        </header>

        <div className="p-8 space-y-8">
          {/* TOP CARDS */}
          <div className="grid grid-cols-4 gap-6">
            <KpiCard title="Global Efficiency" value="42.03%" trend="+2.4% vs prev hour" />
            <KpiCard title="Total Piezas" value={stats.total} hasBar barColor="bg-blue-500" />
            <KpiCard title="Pendientes" value="24,783" hasBar barColor="bg-orange-500" />
            <div className="bg-[#111827] p-6 rounded-xl relative overflow-hidden border border-slate-800/50">
               <div className="flex justify-between items-start">
                  <div>
                    <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Status Active</p>
                    <p className="text-xl font-bold text-green-400">LIVE PULSE</p>
                  </div>
                  <Activity className="text-green-500/50" size={20}/>
               </div>
               <div className="mt-4 flex items-end gap-1 h-12">
                  {[40,70,45,90,65,80].map((h, i) => (
                    <div key={i} className="flex-1 bg-green-500/20 rounded-t-sm" style={{height: `${h}%`}} />
                  ))}
               </div>
               <p className="text-[9px] text-slate-600 mt-2 text-right">NODE_IM_A</p>
            </div>
          </div>

          {/* MIDDLE SECTION: CHART + MATRIX */}
          <div className="grid grid-cols-12 gap-8">
            {/* Gráfico */}
            <div className="col-span-8 bg-[#111827]/40 p-6 rounded-2xl border border-slate-800/30">
              <div className="flex justify-between items-end mb-8">
                <div>
                  <h3 className="text-lg font-bold text-white mb-1">Kinetic Pulse Chart</h3>
                  <p className="text-xs text-slate-500">Hourly Arribo vs Bipeo Dynamics</p>
                </div>
               <div className="flex gap-4 text-[10px] font-bold uppercase tracking-tighter">
                    <span className="flex items-center gap-2"><div className="w-2 h-2 bg-[#2563eb] rounded-full" /> ARRIBO</span>
                    <span className="flex items-center gap-2"><div className="w-2 h-2 bg-[#93c5fd] rounded-full" /> BIPEO</span>
                    </div>

              </div>
              <div className="h-80">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={stats.chartData} barGap={0}>
                    <CartesianGrid vertical={false} stroke="#1e293b" strokeDasharray="3 3" />
                    <XAxis dataKey="hora" axisLine={false} tickLine={false} tick={{fill: '#475569', fontSize: 10}} dy={10} />
                    <YAxis hide />
