const TableRow = ({ hora, etiquetado, piezas, usuarios }) => {
  const avance = Math.round((piezas / etiquetado) * 100);
  // Colores exactos de la imagen: turquesa para optimal, naranja vibrante para watch
  const colorBarra = avance >= 90 ? 'bg-[#00f2ad]' : 'bg-[#ff6b00]';
  const colorTexto = avance >= 90 ? 'text-[#00f2ad]' : 'text-[#ff6b00]';

  return (
    <tr className="border-b border-slate-800/40 text-[12px] hover:bg-white/5 transition-colors">
      <td className="py-5 pl-2 text-slate-500 font-medium">{hora}</td>
      <td className="py-5 font-semibold text-slate-300">{etiquetado.toLocaleString()}</td>
      <td className="py-5 font-semibold text-slate-300">{piezas.toLocaleString()}</td>
      <td className="py-5 w-64">
        <div className="flex items-center gap-4">
          <div className="flex-1 h-[3px] bg-slate-800 rounded-full">
            <div className={`h-full ${colorBarra} shadow-[0_0_8px_rgba(0,0,0,0.5)]`} style={{ width: `${avance}%` }} />
          </div>
          <span className="w-10 text-right font-bold text-slate-200">{avance}%</span>
        </div>
      </td>
      <td className="py-5 text-center text-slate-300">{usuarios}</td>
      <td className={`py-5 pr-2 text-right font-black italic tracking-tighter ${colorTexto}`}>
        {avance >= 90 ? 'OPTIMAL' : 'WATCH'}
      </td>
    </tr>
  );
};

